module alu(
    input [31:0] a, b,
    input [5:0] aluc,
    output reg [31:0] r,
    output reg zero, carry, negative, overflow, flag
);

    reg [31:0] res_reg;

    wire [4:0] shift_amount;

    assign shift_amount = (aluc == 6'b000000 || aluc == 6'b000010 || aluc == 6'b000011) ? {a[7:0], a[6:0]} : 5'b0;

    always @(*) begin
        case (aluc)
            6'b100000: res_reg = a + b; 
            6'b100001: res_reg = a - b; 
            6'b100010: res_reg = a & b; 
            6'b100011: res_reg = a | b; 
            6'b100100: res_reg = a ^ b; 
            6'b100111: res_reg = ~(a | b); 
            6'b101010: res_reg = (a < b) ? 32'h8000_0000 : 32'h0000_0000; 
            6'b101011: res_reg = (a < b) ? 32'h0000_0001 : 32'h0000_0000; 
            6'b000000: res_reg = a << shift_amount; 
            6'b000010: res_reg = a >> shift_amount; 
            6'b000011: res_reg = a >>> shift_amount; 
            6'b000100: res_reg = $signed(a) <<< shift_amount; 
            6'b000110: res_reg = $signed(a) >>> shift_amount; 
            6'b000111: res_reg = $signed(a) >>> shift_amount; 
            default: res_reg = 32'h0000_0000;
    endcase

    assign r = res_reg;
    assign zero = ~|res_reg;
    assign negative = res_reg[31];
    assign overflow = ((~&res_reg && (~&(~res_reg))) != 0);
    assign flag = (aluc == 6'b101010) ? 1'b1 :
                  (aluc == 6'b101011) ? 1'b1 :
                  1'b0;

end // Auto-repaired
endmodule
